  memset(&call, 0, sizeof(call));
  IREE_RETURN_IF_ERROR(
    iree_runtime_call_initialize_by_name(
        session, iree_make_cstring_view(kMainFunctionName), &call),
    "init call");

  iree_vm_list_t* inputs;
  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
                                    iree_allocator_system(), &inputs));
  iree_vm_value_t arg_value = iree_vm_value_make_i32(1);
  IREE_RETURN_IF_ERROR(iree_vm_list_push_value(inputs, &arg_value));

  iree_vm_list_t* outputs = NULL;
  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
                                    iree_allocator_system(), &outputs));

  printf("tune...ok\n");
//  clock_t start, end;
//  start = clock();
#ifdef PF_COUNTER
    startPFM;
#endif
  IREE_CHECK_OK(
      iree_runtime_session_call_by_name(session, iree_make_cstring_view(kMainFunctionName), inputs, outputs));
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif
//  end = clock();
//  double diff = end - start; // ms
  printf(" PASS1 \n");
//  printf("seconds : %f  PASS2 \n", diff / CLOCKS_PER_SEC );
  iree_runtime_call_deinitialize(&call);

  // Cleanup session and instance.
  iree_hal_device_release(device);
  iree_runtime_session_release(session);
  iree_runtime_instance_release(instance);
  iree_vm_module_release(module);

  return status;
}

