"""Base workflow protocol for command pattern implementation.

Workflows encapsulate different input modes and provide a uniform interface for execution.
"""

from typing import Protocol
from argparse import Namespace, ArgumentParser


class Workflow(Protocol):
    """Protocol for workflow classes.

    Each workflow represents a distinct input mode (e.g., task-based pipeline execution).

    Example:
